import java.io.IOException;
import java.util.Scanner;

public class CommandInjectionFixed {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a file name: ");
        String fileName = scanner.nextLine();

        try {
            // Secure way using ProcessBuilder
            Process process = new ProcessBuilder("cat", fileName).start();

            // Reading the output of the command
            Scanner processScanner = new Scanner(process.getInputStream());
            while (processScanner.hasNextLine()) {
                System.out.println(processScanner.nextLine());
            }

        } catch (IOException e) {
            e.printStackTrace();
        }

        scanner.close();
    }
}

### Explanation:
취약유형: Command Injection
